-- Наполнение FAQ новыми вопросами по функциям, добавленным 22-24 июля:
-- приватные сообщения (спойлеры), лаунчер-бейдж и уведомления, право просмотра
-- чужих приватных сообщений, умная сортировка задач на доске.
INSERT INTO faq_items (question, answer, sort_order) VALUES
('Что такое приватное сообщение и как им пользоваться?', '<p>Приватное сообщение — это текст, который видят только автор и выбранный адресат (плюс участники с правом «Просмотр чужих приватных сообщений»). Добавить его можно в описании задачи (кнопка с перечёркнутым глазом рядом с полем «Описание» — видна только в режиме редактирования) и при написании нового комментария (такая же иконка рядом с кнопкой отправки).</p>
<p>В теле описания или комментария приватное сообщение отображается как спойлер: по умолчанию скрыто и подписано «Приватно для Имени — нажмите, чтобы показать», по клику текст раскрывается. Технически текст надёжно скрыт на уровне сервера — он не передаётся в браузер тем, кому не адресован, поэтому спойлер не хранит секрет «по договорённости», а по-настоящему не долетает до чужого браузера.</p>
<p>Удалить приватное сообщение может автор или администратор — крестик удаления показывается только в редакторе описания задачи; в самом описании (режим просмотра) и у сообщений, прикреплённых к комментариям, доступно только чтение.</p>', 24),
('Что означает право «Просмотр чужих приватных сообщений»?', '<p>По умолчанию текст приватного сообщения видят только его автор и адресат — даже администраторы не могут прочитать чужую приватную переписку. Право «Просмотр чужих приватных сообщений» (раздел «Приватные сообщения» в дереве прав участника) снимает это ограничение для конкретного человека: он сможет раскрывать любые спойлеры в задачах, к которым имеет доступ.</p>
<p>Право можно выдать или забрать индивидуально любому участнику, включая администраторов — оно не привязано жёстко к роли и настраивается точно так же, как остальные права команды.</p>', 25),
('Что означает бейдж «Требуется заливки в лаунчер»?', '<p>Бейдж появляется на карточке задачи, если к ней прикреплён хотя бы один файл патча (из раздела «Патчи») и при этом задача находится в состоянии, готовом к раскатке — колонка «К рестарту» или статус деплоя «Можно заливать на лайв» — но ещё не отмечена как загруженная. Как только файлы залиты в лаунчер, нужно нажать кнопку «Отметить как загружено в лаунчер» в карточке задачи — бейдж сменится на зелёный «Загружено в лаунчер».</p>
<p>Если после отметки статус деплоя или колонка задачи снова меняются, отметка «Загружено» автоматически сбрасывается — так система напоминает залить актуальную сборку заново.</p>', 26),
('Кто получает уведомление о задачах, требующих заливки в лаунчер?', '<p>Уведомление (в приложении и в Telegram) приходит всем участникам с правом «Уведомление о лаунчере» (раздел «Лаунчер» в дереве прав) в момент, когда у задачи появляется бейдж «Требуется заливки в лаунчер» — то есть при смене статуса деплоя или колонки на подходящий, при снятии отметки «Загружено», а также при прикреплении файла патча к уже готовой к раскатке задаче.</p>
<p>Право выдаётся и забирается индивидуально в разделе управления командой, как и остальные права — не обязательно быть администратором, чтобы его получить.</p>', 27),
('Как работает умная сортировка задач на доске?', '<p>Режим «Умная сортировка» (выбирается через меню сортировки над доской, иконка со звёздочками) — сортировка по умолчанию. Сначала показываются самые горящие задачи: с высоким или критическим приоритетом и/или с дедлайном, который уже истёк либо наступает в течение суток. Внутри этой группы задачи упорядочены по сроку дедлайна — у кого раньше, та выше.</p>
<p>Остальные задачи идут следом, отсортированные по дате создания (более старые — выше), чтобы они не терялись в общем потоке. Доступны и другие режимы сортировки — по приоритету, сначала новые, сначала старые — переключаются там же, в меню сортировки.</p>', 28);
